import{_ as a,o as n,c as s,ae as i}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Contributing","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md"}'),t={name:"contributing.md"};function p(l,e,o,d,r,c){return n(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h1><p>Contributions are welcome — bug reports, new steps, documentation improvements, or fixes.</p><h2 id="project-layout" tabindex="-1">Project layout <a class="header-anchor" href="#project-layout" aria-label="Permalink to &quot;Project layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pipectl/</span></span>
<span class="line"><span>├── cmd/pipectl/              CLI entrypoint (cobra)</span></span>
<span class="line"><span>├── internal/</span></span>
<span class="line"><span>│   ├── engine/               Runtime execution</span></span>
<span class="line"><span>│   │   ├── payload/          JSON, JSONL, CSV payload types</span></span>
<span class="line"><span>│   │   └── steps/            One package per step implementation</span></span>
<span class="line"><span>│   └── pipeline/</span></span>
<span class="line"><span>│       ├── spec/             YAML schema types + step registry</span></span>
<span class="line"><span>│       ├── plan/             Compiles spec steps into engine steps</span></span>
<span class="line"><span>│       └── integration_test.go</span></span>
<span class="line"><span>├── examples/                 Runnable example pipelines</span></span>
<span class="line"><span>├── playbooks/                Task-level implementation guides</span></span>
<span class="line"><span>└── website/                  VitePress documentation site</span></span></code></pre></div><h3 id="dependency-boundaries" tabindex="-1">Dependency boundaries <a class="header-anchor" href="#dependency-boundaries" aria-label="Permalink to &quot;Dependency boundaries&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd → internal/pipeline → internal/pipeline/{spec,plan}</span></span>
<span class="line"><span>internal/pipeline/plan → internal/engine + internal/engine/steps/*</span></span>
<span class="line"><span>internal/engine/steps/* → internal/engine/payload</span></span></code></pre></div><ul><li><code>spec</code> parses and validates YAML — it does not execute steps.</li><li><code>engine</code> executes steps — it does not parse YAML.</li><li>Step packages must not import <code>internal/pipeline/*</code>.</li></ul><h2 id="running-tests" tabindex="-1">Running tests <a class="header-anchor" href="#running-tests" aria-label="Permalink to &quot;Running tests&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./...</span></span></code></pre></div><p>Regenerate golden files after changing step output:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TestStepPipelines</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -update</span></span></code></pre></div><h2 id="adding-a-new-step" tabindex="-1">Adding a new step <a class="header-anchor" href="#adding-a-new-step" aria-label="Permalink to &quot;Adding a new step&quot;">​</a></h2><p>The detailed checklist lives in <a href="https://github.com/pipectl/pipectl/blob/main/playbooks/add-new-step.md" target="_blank" rel="noreferrer"><code>playbooks/add-new-step.md</code></a>. The short version:</p><ol><li>Add spec type in <code>internal/pipeline/spec/</code></li><li>Register it in <code>internal/pipeline/spec/unmarshal.go</code></li><li>Add the engine step in <code>internal/engine/steps/&lt;name&gt;/</code></li><li>Wire it in <code>internal/pipeline/plan/builder.go</code></li><li>Add unit tests in the step package</li><li>Add integration test pipeline(s) and golden files in <code>internal/pipeline/testdata/</code></li><li>Wire the test case into <code>TestStepPipelines</code></li><li>Add a step page under <code>website/docs/steps/</code></li></ol><p>Each payload format a step supports (JSON, JSONL, CSV) should have its own integration test case.</p><h2 id="adding-a-new-payload-format" tabindex="-1">Adding a new payload format <a class="header-anchor" href="#adding-a-new-payload-format" aria-label="Permalink to &quot;Adding a new payload format&quot;">​</a></h2><p>See <a href="https://github.com/pipectl/pipectl/blob/main/playbooks/add-payload-format.md" target="_blank" rel="noreferrer"><code>playbooks/add-payload-format.md</code></a>.</p><h2 id="quality-bar" tabindex="-1">Quality bar <a class="header-anchor" href="#quality-bar" aria-label="Permalink to &quot;Quality bar&quot;">​</a></h2><p>Before submitting a pull request:</p><ul><li>Architecture boundaries are preserved</li><li>New config surfaces are validated close to parse time</li><li>Tests are added or updated and pass locally</li><li>Testdata pipelines and golden files are added or updated</li><li>The relevant docs page under <code>website/docs/</code> is updated</li></ul><h2 id="opening-a-pull-request" tabindex="-1">Opening a pull request <a class="header-anchor" href="#opening-a-pull-request" aria-label="Permalink to &quot;Opening a pull request&quot;">​</a></h2><p>Target the <code>main</code> branch. Include a brief description of what the PR does and why.</p>`,22)])])}const g=a(t,[["render",p]]);export{u as __pageData,g as default};
